// Get the data from table_2 mapping
const fields = $('Fields mapping').first().json;

// Determine which text to analyze - prioritize clean_text, fall back to image_caption
let textToAnalyze = fields.text || fields.image_caption || '';

// Convert to lowercase if text exists
if (textToAnalyze) {
  textToAnalyze = textToAnalyze.toLowerCase();
}

const pidginMarkers = [
  'dey', 'wan', 'make we', 'abeg', 'sha', 'run am', 'don',
  'oya', 'how far', 'no forget', 'wetin', 'fes', 'abi'
];

// Check if we have text to analyze
let detectedLanguage = 'en'; // Default to English

if (textToAnalyze) {
  const isPidgin = pidginMarkers.some(word => textToAnalyze.includes(word));
  detectedLanguage = isPidgin ? 'pidgin' : 'en';
}

return {
  ...$json,
  detected_language: detectedLanguage
};

const transcriptionText = $json.text || '';

return {
  json: {
    messages: [{ text: { body: transcriptionText } }]
  }
};

// Data has already been validated and merged
const data = $input.first().json;

// Validate required fields one more time
if (!data.chat_id || !data.fullname || !data.username || !data.email || !data.interests || data.interests.length === 0) {
  throw new Error('Missing required fields after validation');
}

return {
  json: {
    chat_id: data.chat_id,
    fullname: data.fullname,
    username: data.username,
    email: data.email,
    interests: data.interests,
    token: data.token,
    interests_count: data.interests.length
  }
};

