    <script>
        const WEBHOOK_URL = '[URL]';

        // Extract token from table_6
        const urlParams = new URLSearchParams(window.location.search);
        const token = urlParams.get('token');

        // Validate token exists
        if (!token) {
            document.querySelector('.container').innerHTML = \`
