            \`;
        }

        const INTERESTS_LIST = [
            'Music', 'Movies', 'News', 'Tech', 'Wizkid', 'Gadgets', 'Entertainment',
            'Social Media', 'Business', 'Investment', 'Finance', 'Davido', 'Burna Boy',
            'Afrobeats', 'Football', 'Basketball', 'Sports', 'Gaming', 'Anime', 'Fashion',
