            wrapper.className = 'interest-input-wrapper';
            wrapper.innerHTML = \`
                <div class="autocomplete-wrapper" style="flex: 1;">
                    <input type="text" class="interest-input" data-index="\${index}" placeholder="Interest..." required>
                    <div class="autocomplete-list"></div>
