            const input = wrapper.querySelector('.interest-input');
            const autocompleteList = wrapper.querySelector('.autocomplete-list');
            const removeBtn = wrapper.querySelector('.remove-interest');

            input.addEventListener('input', (e) => {
                const value = e.target.value.toLowerCase();
                autocompleteList.innerHTML = '';

                if (value.length > 0) {
                    const filtered = INTERESTS_LIST.filter(item => 
                        item.toLowerCase().includes(value)
                    ).slice(0, 10);

                    if (filtered.length > 0) {
                        filtered.forEach(item => {
                            const div = document.createElement('div');
                            div.className = 'autocomplete-item';
                            div.textContent = item;
                            div.addEventListener('mousedown', (e) => {
                                e.preventDefault();
                                input.value = item;
                                autocompleteList.classList.remove('show');
                            });
                            autocompleteList.appendChild(div);
                        });
                        autocompleteList.classList.add('show');
                    } else {
                        autocompleteList.classList.remove('show');
                    }
                } else {
                    autocompleteList.classList.remove('show');
                }
            });

            input.addEventListener('blur', () => {
                setTimeout(() => {
                    autocompleteList.classList.remove('show');
                }, 300);
            });

            removeBtn.addEventListener('click', () => {
                wrapper.remove();
                interestCount--;
                updateAddButton();
            });

            return wrapper;
