                document.getElementById('fullname-error').classList.add('show');
                isValid = false;
            } else {
                fullname.classList.remove('error');
                document.getElementById('fullname-error').classList.remove('show');
            }

            const username = document.getElementById('username');
            if (!username.value.trim()) {
                username.classList.add('error');
                document.getElementById('username-error').classList.add('show');
                isValid = false;
            } else {
                username.classList.remove('error');
                document.getElementById('username-error').classList.remove('show');
            }

            const email = document.getElementById('email');
            if (!validateEmail(email.value.trim())) {
                email.classList.add('error');
                document.getElementById('email-error').classList.add('show');
                isValid = false;
            } else {
                email.classList.remove('error');
                document.getElementById('email-error').classList.remove('show');
            }

            const interestInputs = document.querySelectorAll('.interest-input');
            const interests = [];
            let hasEmptyInterest = false;

            interestInputs.forEach(input => {
                const value = input.value.trim();
                if (!value) {
                    hasEmptyInterest = true;
                    input.classList.add('error');
                } else {
                    input.classList.remove('error');
                    interests.push(value);
                }
            });

            if (interests.length === 0 || hasEmptyInterest) {
                document.getElementById('interests-error').classList.add('show');
                isValid = false;
            } else {
                document.getElementById('interests-error').classList.remove('show');
            }

            if (isValid) {
                const formData = {
                    token: token,  // ← THIS WAS MISSING - NOW ADDED
                    fullname: fullname.value.trim(),
                    username: username.value.trim(),
                    email: email.value.trim(),
                    interests: interests
                };

                try {
                    const response = await fetch(WEBHOOK_URL, {
                        method: 'POST',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                        body: JSON.stringify(formData)
                    });

                    if (response.ok) {
                        document.getElementById('onboardingForm').style.display = 'none';
                        document.getElementById('successMessage').classList.add('show');
                    } else {
                        const errorData = await response.json().catch(() => ({}));
                        alert(errorData.error || 'Submission failed. Please try again.');
                    }
                } catch (error) {
                    console.error('Error:', error);
                    alert('An error occurred. Please try again.');
                }
            }
        });
    </script>
</body>
</html>`;

