const lookupResult = $input.first().json;
const formData = $('Onboarding Webhook (POST)').first().json.body;

// Check if token lookup returned a result
if (!lookupResult || !lookupResult.chat_id) {
  // Token is invalid, expired, or already used
  return {
    json: {
      error: true,
      message: 'Invalid or expired onboarding token. Please request a new link from table_9',
      http_status: 400
    }
  };
}

// Token is valid - merge the data
return {
  json: {
    error: false,
    chat_id: lookupResult.chat_id,
    fullname: formData.fullname,
    username: formData.username,
    email: formData.email,
    interests: formData.interests,
    token: formData.token
  }
};

const response = $input.item.json.output;

let extractedData;
try {
  extractedData = JSON.parse(response);
} catch {
  const match = response.match(/\{[\s\S]*\}/);
  if (match) extractedData = JSON.parse(match[0]);
  else throw new Error('Could not parse agent response');
}

const accounts = extractedData.accounts || [];
accounts.forEach(account => {
  if (account.account_number) {
    const cleaned = String(account.account_number).replace(/\D/g, '');
    account.account_number_cleaned = cleaned;
    account.is_valid = cleaned.length === 10;
  }
});

const isFinancial = extractedData.is_financial === true;
const caption = $input.item.json.caption || '';

return [{
  json: {
    is_financial: isFinancial,
    financial_type: extractedData.financial_type || 'none',
    accounts,
    count: accounts.length,
    text: isFinancial
      ? accounts.length > 0
        ? `User sent a financial image. Extracted accounts: ${JSON.stringify(accounts)}. Type: ${extractedData.financial_type}. Context: ${extractedData.suggested_response_context}`
        : `User sent a financial image (${extractedData.financial_type}) but no accounts extracted. Description: ${extractedData.image_description}`
      : `User sent an image. Description: ${extractedData.image_description}.${caption ? ' Caption: ' + caption : ''}`,
    image_description: extractedData.image_description,
    suggested_response_context: extractedData.suggested_response_context,
    // Pass through user context for Fields mapping
    caption: caption
  }
}];
